using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Preserve the EF8 discriminator property name (EF9 defaults to "$type")
            entity.HasDiscriminator<string>("Discriminator");

            // Preserve the EF8 compound id format "Blog|1" (EF9 defaults to key-only)
            entity.HasRootDiscriminatorInJsonId(true);

            // HasIndex removed — Cosmos DB throws at startup in EF9.
            // Manage indexing via the Azure Portal or Bicep indexing policy.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

